uint8_t current_task = 0;//idle task is running initially
uint32_t g_tick_count =0;

typedef struct{
	uint32_t psp_value;
	uint32_t block_count;
	uint8_t current_state;
	void (*task_handlers)(void);
}TCB_t;

TCB_t user_tasks[MAX_TASKS];

int main(void)
{
	//
	enable_processor_faults();

	init_schedular_stack(SCHED_STACK_START);

	init_tasks_stack();//task stack init and to store dummy stack frames
	led_init_all();
	init_systick_timer(TICK_HZ);
	/*---------------------stack using psp-------------------*/

	switch_sp_to_psp();
	idle_handler();
    /* Loop forever */
	for(;;);
}
